import anthropic, json

client = anthropic.Anthropic()

TOOL = {
    "name": "search_products",
    "description": (
        "Search the product catalogue by keyword, category, or price range. "
        "Returns up to 20 products with name, price, stock level, and SKU. "
        "Use when the user asks about available products, pricing, or inventory."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "query":    {"type": "string", "description": "Search term"},
            "category": {"type": "string", "description": "Category filter (optional)"},
        },
        "required": ["query"]
    }
}

# Ask the model to describe the tool — no user task involved
resp = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=512,
    tools=[TOOL],
    messages=[{
        "role": "user",
        "content": (
            "You have access to a tool. In one paragraph, explain: "
            "(1) what the tool does, (2) what it returns, and (3) give two example user requests "
            "where you would use it."
        )
    }]
)

for b in resp.content:
    if b.type == "text":
        print(b.text)

