import anthropic, json

client = anthropic.Anthropic()

def evaluate_tool_selection(tools: list[dict], test_cases: list[dict]) -> dict:
    """
    Run a set of test prompts and check whether the model picks the expected tool.
    Returns a pass/fail report per test case.
    """
    results = []
    for case in test_cases:
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=256,
            tools=tools,
            messages=[{"role": "user", "content": case["prompt"]}]
        )
        called = [b.name for b in resp.content if b.type == "tool_use"]
        expected = case["expected_tool"]
        passed = expected in called
        results.append({
            "prompt":   case["prompt"],
            "expected": expected,
            "called":   called,
            "passed":   passed
        })

    passed_count = sum(1 for r in results if r["passed"])
    print(f"Passed: {passed_count}/{len(results)}")
    for r in results:
        status = "✓" if r["passed"] else "✗"
        print(f"  {status} '{r['prompt'][:50]}...'")
        if not r["passed"]:
            print(f"      Expected: {r['expected']}, Got: {r['called']}")
    return results

TOOLS = [
    {
        "name": "search_knowledge_base",
        "description": "Search internal company policies and FAQs.",
        "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}
    },
    {
        "name": "web_search",
        "description": "Search the public internet for current information.",
        "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}
    }
]

TEST_CASES = [
    {"prompt": "What is our parental leave policy?",          "expected_tool": "search_knowledge_base"},
    {"prompt": "What is the current Python stable version?",  "expected_tool": "web_search"},
    {"prompt": "How do I submit an expense report?",          "expected_tool": "search_knowledge_base"},
]

evaluate_tool_selection(TOOLS, TEST_CASES)

